define bfloat @bf16_frem(bfloat %x) {
  %t1 = fpext bfloat %x to float
  %t2 = frem float %t1, 6.281250e+00
  %t3 = fptrunc float %t2 to bfloat
  ret bfloat %t3
}

define <4 x bfloat> @v4bf16_frem_const_x(<4 x bfloat> %x) {
  %t1 = fpext <4 x bfloat> %x to <4 x float>
  %t2 = frem <4 x float> <float 6.281250e+00, float 6.281250e+00, float 6.281250e+00, float 6.281250e+00>, %t1
  %t3 = fptrunc <4 x float> %t2 to <4 x bfloat>
  ret <4 x bfloat> %t3
}

define <4 x bfloat> @v4bf16_frem_x_const(<4 x bfloat> %x) {
  %t1 = fpext <4 x bfloat> %x to <4 x float>
  %t2 = frem <4 x float> %t1, <float 6.281250e+00, float 6.281250e+00, float 6.281250e+00, float 6.281250e+00>
  %t3 = fptrunc <4 x float> %t2 to <4 x bfloat>
  ret <4 x bfloat> %t3
}

define <4 x float> @v4f32_fadd(<4 x float> %a) {
  %1 = fpext <4 x float> %a to <4 x double>
  %2 = fadd <4 x double> %1, <double -1.000000e+00, double -1.000000e+00, double -1.000000e+00, double -1.000000e+00>
  %3 = fptrunc <4 x double> %2 to <4 x float>
  ret <4 x float> %3
}
